"use client";

/**
 * @file Browse page for Moon's Once UI Next user app.
 */

import {useDeferredValue, useMemo, useState} from "react";
import {useMoonJson} from "../../lib/api.js";
import {formatTypeLabel} from "../../lib/routes.js";
import TitleCard from "../TitleCard.jsx";
import {EmptyView, ErrorView, LoadingView} from "../StateView.jsx";

/**
 * Render the browse surface.
 *
 * @returns {import("react").ReactNode}
 */
export const BrowsePageClient = () => {
  const {loading, error, data} = useMoonJson("/api/moon-v3/user/library", {fallback: {titles: []}});
  const [search, setSearch] = useState("");
  const deferredSearch = useDeferredValue(search);

  const filteredTitles = useMemo(() => {
    const key = deferredSearch.trim().toLowerCase();
    const titles = Array.isArray(data?.titles) ? data.titles : [];
    if (!key) {
      return titles;
    }
    return titles.filter((title) =>
      [
        title.title,
        title.summary,
        title.libraryTypeLabel,
        ...(Array.isArray(title.aliases) ? title.aliases : []),
        ...(Array.isArray(title.tags) ? title.tags : [])
      ]
        .join(" ")
        .toLowerCase()
        .includes(key)
    );
  }, [data?.titles, deferredSearch]);

  const grouped = useMemo(() => {
    const next = new Map();
    for (const title of filteredTitles) {
      const key = title.libraryTypeSlug || title.mediaType || "manga";
      if (!next.has(key)) {
        next.set(key, []);
      }
      next.get(key).push(title);
    }
    return Array.from(next.entries());
  }, [filteredTitles]);

  if (loading) {
    return <LoadingView label="Moon is indexing every title so browse can stay fast while you search." />;
  }

  if (error) {
    return <ErrorView detail={error} />;
  }

  return (
    <div className="moon-page-grid">
      <section className="moon-panel moon-section">
        <div className="moon-section-head">
          <div>
            <span className="moon-kicker">Browse</span>
            <h2>Search the whole reading stack</h2>
          </div>
        </div>
        <input
          className="moon-search-bar"
          type="search"
          value={search}
          onChange={(event) => setSearch(event.target.value)}
          placeholder="Search titles, aliases, tags, or type"
        />
      </section>
      {grouped.length ? grouped.map(([typeSlug, titles]) => (
        <section key={typeSlug} className="moon-panel moon-section">
          <div className="moon-section-head">
            <div>
              <span className="moon-kicker">{formatTypeLabel(typeSlug)}</span>
              <h2>{titles.length} surfaced title{titles.length === 1 ? "" : "s"}</h2>
            </div>
          </div>
          <div className="moon-card-row">
            {titles.map((title) => (
              <TitleCard key={title.id} title={title} />
            ))}
          </div>
        </section>
      )) : (
        <EmptyView title="No titles match that search" detail="Try a broader title, alias, tag, or type filter." />
      )}
    </div>
  );
};

export default BrowsePageClient;
